-- ============================================================
-- V2: TOS items table + art_activity restructure
-- ============================================================

-- 1. TOS reference table
CREATE TABLE tos_item (
    seq INTEGER PRIMARY KEY,
    grupo VARCHAR(60) NOT NULL,
    subgrupo VARCHAR(200) NOT NULL,
    obra_servico VARCHAR(200) NOT NULL,
    complemento VARCHAR(200)
);

-- 2. Seed TOS data (1614 entries)

-- Full-text search index
CREATE INDEX idx_tos_item_search ON tos_item USING gin(
    to_tsvector('portuguese', grupo || ' ' || subgrupo || ' ' || obra_servico || ' ' || COALESCE(complemento, ''))
);

-- 3. Restructure art_activity to match TOS
ALTER TABLE art_activity
    DROP COLUMN nivel_atuacao,
    DROP COLUMN atividade_profissional_code,
    DROP COLUMN atividade_profissional_desc,
    DROP COLUMN obra_servico_code,
    DROP COLUMN obra_servico_desc;

ALTER TABLE art_activity
    ADD COLUMN atividade VARCHAR(150) NOT NULL DEFAULT '',
    ADD COLUMN grupo VARCHAR(60) NOT NULL DEFAULT '',
    ADD COLUMN subgrupo VARCHAR(200) NOT NULL DEFAULT '',
    ADD COLUMN obra_servico VARCHAR(200) NOT NULL DEFAULT '';

ALTER TABLE art_activity
    ALTER COLUMN atividade DROP DEFAULT,
    ALTER COLUMN grupo DROP DEFAULT,
    ALTER COLUMN subgrupo DROP DEFAULT,
    ALTER COLUMN obra_servico DROP DEFAULT;